// CalculateDiscount executes a JavaScript discount rule script in a Goja VM,
// with order object injected as a global variable, and returns the resulting discount amount.
func CalculateDiscount(script string, order map[string]interface{}) (float64, error) {
	vm := goja.New()

	// Inject order object as a global variable in the VM
	vm.Set("order", order)

	// Wrap script in an IIFE to allow return statements
