	// Set interrupt to check context timeout
	intChan := make(chan struct{}, 1)
	vm.Interrupt = intChan
	go func() {
		select {
		case <-ctx.Done():
			intChan <- struct{}{}
		}
	}()

	// Execute the wrapped script
	result, err := vm.RunString(wrappedScript)
	if err != nil {
		return 0.0, fmt.Errorf("script execution error: %w", err)
	}

	// Convert result to float64
